import type { EmojiCategory, EmojiEntry } from '../../data/emoji_data';
import {
  EMOJI_CATEGORIES,
  EMOJI_CATEGORY_LABELS,
  EMOJI_CATEGORY_ORDER,
  MOCK_EMOJIS,
} from '../../data/emoji_data';
