                : prevInfo.sectionStart + prevInfo.sectionLength - 1;
            }

            return prev;
          });
          break;
        }
        case 'Enter': {
          e.preventDefault();
          handleCopyEmoji();
          break;
        }
      }
    }

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [
    totalCount,
    actionsOpen,
    handleCopyEmoji,
    sections,
  ]);

  const sectionBoundaries = useMemo(() => {
    const boundaries: {
      start: number;
      length: number;
