                            key={`${section.title}-${emoji.char}`}
                            id={`emoji-item-${idx}`}
                            className={`emoji-picker__cell${isActive ? ' emoji-picker__cell--active' : ''}`}
                            role="option"
                            aria-selected={isActive}
                            aria-label={emoji.name}
                            data-emoji-index={idx}
                            onClick={() => {
                              setActiveIndex(idx);
                              handleCopyEmoji(emoji);
                            }}
