export function FileSearchView() {
  const nav = useNavigation();
  const [entries, setEntries] = useState<FileEntry[]>(
    isTauri ? [] : MOCK_FILE_ENTRIES,
  );
  const [query, setQuery] = useState('');
  const [filterValue, setFilterValue] = useState('all');
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [actionsOpen, setActionsOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const { items: hudItems, show: showHUD } = useHUD();
  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
  const now = useMemo(() => new Date(), []);
  const searchRequestRef = useRef(0);

  useEffect(() => {
    if (!isTauri) return;

    setIsLoading(true);

    const timer = setTimeout(() => {
      const requestId = ++searchRequestRef.current;

      getPlatform()
        .files.searchFiles(query)
        .then(results => {
          if (requestId !== searchRequestRef.current) return;
          setEntries(results.map(mapSearchResult));
        })
        .catch(() => {
          if (requestId !== searchRequestRef.current) return;
          setEntries([]);
        })
        .finally(() => {
          if (requestId !== searchRequestRef.current) return;
          setIsLoading(false);
        });
    }, 250);

    return () => clearTimeout(timer);
  }, [query]);

  const filtered = useMemo(() => {
    let items = entries;
    if (filterValue !== 'all') {
      items = items.filter(e => e.fileType === filterValue);
    }
    if (!isTauri && query) {
      items = items.filter(
        e => fuzzyMatch(query, e.name) || fuzzyMatch(query, e.path),
      );
    }
    return items;
  }, [
    entries,
    query,
    filterValue,
  ]);

  const folders = useMemo(
    () => filtered.filter(e => e.fileType === 'folder'),
    [filtered],
  );
  const files = useMemo(
    () => filtered.filter(e => e.fileType !== 'folder'),
    [filtered],
  );
  const totalItemCount = filtered.length;

  const flatItems = useMemo(
    () => [
      ...folders,
      ...files,
    ],
    [
      folders,
      files,
    ],
  );
